/**
 * @fileoverview HintBox barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/HintBox
 */
import { default as razyui } from '../index.js';
import { HintBoxDef as DEF } from './HintBox.def.js';
import HintBox from './HintBox/index.js';

// ── Module registration ──
// Register the HintBox component to the global razyui object
razyui.HintBox = HintBox;

// ── JIT Component Definition registration ──
// Register the component definition with the JIT compiler if available
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// ── Custom Element registration ──
/**
 * Registers the HintBox component as a custom element.
 * This allows the component to be used as an HTML tag (e.g., <rui-hint-box>).
 * 
 * @returns {Promise<void>} A promise that resolves when the element is registered.
 */
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, HintBox);
}

export default HintBox;
export const stylesheet = null;
