/**
 * @fileoverview HintBox component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * event handler abstractions, and Custom Element metadata.
 *
 * Used by:
 *   - HintBox.js (imports for SM config + handler dispatch)
 *   - JIT.defineComponent() (registers tokens + CE)
 *
 * @module module/HintBox.def
 */

import razyui from '../index.js';
import { PART } from './HintBox/constants.js';

export const HintBoxDef = {
    name: 'HintBox',
    tag: 'rui-hint-box',

    // -------------------------------------------------------------------------
    //  Design Tokens
    // -------------------------------------------------------------------------
    tokens: {
        prefix: 'hb',
        tokens: {
            'radius':           { ref: 'radius.md',          description: 'Dropdown border radius' },
            'max-height':       { value: '240px',            description: 'Max dropdown height' },
            'padding-x':        { value: '0',                description: 'Dropdown horizontal padding' },
            'padding-y':        { value: '4px',              description: 'Dropdown vertical padding' },
            'font-size':        { ref: 'font.size-sm',       description: 'Dropdown font size' },
            'item-padding-x':   { value: '0.75rem',          description: 'Item horizontal padding' },
            'item-padding-y':   { value: '0.45rem',          description: 'Item vertical padding' },
            'item-line-height': { value: '1.4',              description: 'Item line height' },
            'match-radius':     { value: '2px',              description: 'Match highlight radius' },
            'bg':               { ref: 'color.bg',           description: 'Dropdown background' },
            'border':           { ref: 'color.border',       description: 'Dropdown border color' },
            'shadow':           { ref: 'shadow.lg',          description: 'Dropdown shadow' },
            'text':             { ref: 'color.text',         description: 'Item text color' },
            'bg-hover':         { ref: 'color.bg-hover',     description: 'Item hover background' },
            'accent':           { ref: 'color.accent',       description: 'Match highlight text color' },
            'accent-subtle':    { ref: 'color.accent-subtle', description: 'Match highlight background' },
            'font-stack':       { ref: 'font.family',        description: 'Font family' },
            'z-index':          { ref: 'z-index.dropdown',   description: 'Overlay z-index' },
        },
    },

    // -------------------------------------------------------------------------
    //  State Machine (dropdown visibility)
    // -------------------------------------------------------------------------
    states: {
        initial: 'closed',
        states: {
            closed: {
                on: { OPEN: 'open' },
            },
            open: {
                on: { CLOSE: 'closed' },
            },
        },
        effects: {
            open(ctx) {
                const { dropdown } = ctx;
                if (dropdown) razyui(dropdown).addClass('is-visible');
            },
            closed(ctx) {
                const { dropdown } = ctx;
                if (dropdown) razyui(dropdown).removeClass('is-visible');
            },
        },
    },

    // -------------------------------------------------------------------------
    //  Template Slots
    // -------------------------------------------------------------------------
    template: {
        slots: {
            dropdown: { element: 'div', classes: ['hintbox-dropdown'] },
            item:     { element: 'div', classes: ['hintbox-item'] },
            match:    { element: 'mark', classes: ['hintbox-match'] },
        },
    },

    // -------------------------------------------------------------------------
    //  Event Handlers (abstractions)
    // -------------------------------------------------------------------------
    handlers: {
        input: {
            input(ctx) {
                if (ctx.justSelected) { ctx.justSelected = false; return; }
                ctx.onInput();
            },
            keydown(ctx, e) {
                if (!ctx.isOpen) return;
                const count = ctx.itemCount;
                switch (e.key) {
                    case 'ArrowDown':
                        e.preventDefault();
                        ctx.setActive((ctx.activeIdx + 1) % count);
                        break;
                    case 'ArrowUp':
                        e.preventDefault();
                        ctx.setActive((ctx.activeIdx - 1 + count) % count);
                        break;
                    case 'Enter':
                        e.preventDefault();
                        if (ctx.activeIdx >= 0) ctx.select(ctx.activeIdx);
                        break;
                    case 'Escape':
                        ctx.close();
                        break;
                }
            },
            focus(ctx) {
                if (ctx.justSelected) return;
                if (ctx.inputValue.length >= ctx.minLength) {
                    ctx.onInput();
                }
            },
        },
    },

    // -------------------------------------------------------------------------
    //  Custom Element
    // -------------------------------------------------------------------------
    observedAttrs: ['source', 'min-length', 'delay', 'max-items', 'placeholder'],
    attrMap: {
        'min-length': 'minLength',
        'max-items': 'maxItems',
    },

    jitParts: {
        [PART.DROPDOWN]: PART.DROPDOWN,
        [PART.ITEM]: PART.ITEM,
        [PART.GROUP]: PART.GROUP,
        [PART.MATCH]: PART.MATCH,
    },
};

export default HintBoxDef;
