/**
 * @fileoverview HintBox constants — CSS classes, selectors, default config.
 * @module module/HintBox/constants
 */
import { defineParts } from '../shared/definePart.js';


/** CSS class names */
export const CLS = Object.freeze({
    DROPDOWN: 'hintbox-dropdown',
    ITEM:     'hintbox-item',
    GROUP:    'hintbox-group',
    MATCH:    'hintbox-match',
    VISIBLE:  'is-visible',
    FLIPPED:  'is-flipped',
    ACTIVE:   'is-active',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    source:       [],
    minLength:    1,
    delay:        300,
    maxItems:     10,
    labelKey:     'label',
    valueKey:     'value',
    queryParam:   'q',
    method:       'GET',
    highlight:    true,
    placeholder:  null,
    itemTemplate: null,
    groupKey:     null,
    groupHeader:  null,
    onGroupClick: null,
    onItemClick:  null,
    renderItem:   null,
    onSelect:     null,
    onOpen:       null,
    onClose:      null,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('HintBox', {
    DROPDOWN    : { class: 'hintbox-dropdown', aliases: ['dropdown', 'root', 'container'] },
    ITEM        : { class: 'hintbox-item', aliases: ['item'] },
    GROUP       : { class: 'hintbox-group' },
    MATCH       : { class: 'hintbox-match' },
});

PART.DROPDOWN.jit = 'fixed bg-[var(--hb-bg)] [border:1px_solid_var(--hb-border)] rounded-[var(--hb-radius)] [box-shadow:var(--hb-shadow)] [max-height:var(--hb-max-height)] overflow-y-auto [display:none] [padding:var(--hb-padding-y)_var(--hb-padding-x)] [font-family:inherit] text-[var(--hb-font-size)] {is-visible}:block {is-flipped}:[border-radius:var(--hb-radius)_var(--hb-radius)_0_0]';
PART.ITEM.jit     = '[padding:var(--hb-item-padding-y)_var(--hb-item-padding-x)] text-[var(--hb-font-size)] fg-[var(--hb-text)] cursor-pointer [line-height:var(--hb-item-line-height)] hover:bg-[var(--hb-bg-hover)] {is-active}:bg-[var(--hb-bg-hover)]';
PART.GROUP.jit    = '[padding:var(--hb-item-padding-y)_var(--hb-item-padding-x)] text-[.75rem] fw-600 fg-[var(--hb-text-muted)] [line-height:1.4] cursor-pointer select-none [background:color-mix(in_srgb,var(--hb-bg-hover)_50%,var(--hb-bg))] [border-top:1px_solid_var(--hb-border)] hover:fg-[var(--hb-text)] first:[border-top:none]';
PART.MATCH.jit    = 'bg-[var(--hb-accent-subtle)] fg-[var(--hb-accent)] rounded-[var(--hb-match-radius)] [padding:0_1px]';