/**
 * @fileoverview HintBox view — DOM setup / teardown, dropdown rendering & positioning.
 * @module module/HintBox/view
 */

import razyui from '../../index.js';
import { CLS, PART } from './constants.js';
import { highlightMatch } from './helpers.js';
import { positionFloating } from '../shared/positionFloating.js';
import { setContent } from '../shared/setContent.js';

// ═══════════════════════════════════════
//  Dropdown creation
// ═══════════════════════════════════════

/**
 * Create the floating dropdown element and append it to `document.body`.
 *
 * @returns {Elements} razyui Elements wrapper around the dropdown div
 */
export function createDropdown() {
    const dropdown = razyui.spell('div.hint-box.' + CLS.DROPDOWN, true);
    PART.DROPDOWN.apply(dropdown);
    razyui(document.body).append(dropdown);
    return dropdown;
}

// ═══════════════════════════════════════
//  Rendering
// ═══════════════════════════════════════

/**
 * Render the suggestion list inside the dropdown.
 * Supports optional grouping via `config.groupKey` and custom rendering via `config.renderItem`.
 *
 * @param {Elements} dropdown — Elements wrapper of the dropdown
 * @param {Array}    items    — filtered/fetched suggestion items
 * @param {object}   config   — component configuration
 * @param {string}   query    — current search query
 * @param {object}   callbacks — { onSelect: (idx) => void, onActivate: (idx) => void }
 */
export function renderList(dropdown, items, config, query, callbacks) {
    dropdown.html('');

    // ── Grouped rendering ──
    if (config.groupKey) {
        const groups = new Map();
        items.forEach((item, idx) => {
            const key = razyui.isPO(item) ? (item[config.groupKey] ?? '') : '';
            if (!groups.has(key)) groups.set(key, []);
            groups.get(key).push({ item, idx });
        });

        for (const [groupName, entries] of groups) {
            // Group header
            if (groupName !== '') {
                const header = razyui.spell('div.' + CLS.GROUP, true);
                PART.GROUP.apply(header);
                if (razyui.isFn(config.groupHeader)) {
                    setContent(header, config.groupHeader(groupName));
                } else {
                    header.text(groupName);
                }
                if (razyui.isFn(config.onGroupClick)) {
                    header.on('mousedown', (e) => {
                        if (e.button !== 0) return;
                        e.preventDefault();
                        config.onGroupClick(groupName);
                    });
                }
                dropdown.append(header);
            }

            // Group items
            for (const { item, idx } of entries) {
                dropdown.append(buildItem(item, idx, config, query, callbacks));
            }
        }
        return;
    }

    // ── Flat rendering ──
    items.forEach((item, idx) => {
        dropdown.append(buildItem(item, idx, config, query, callbacks));
    });
}

/**
 * Build a single dropdown item element.
 *
 * @param {*}      item      — data item
 * @param {number} idx       — item index
 * @param {object} config    — component configuration
 * @param {string} query     — current search query
 * @param {object} callbacks — { onSelect, onActivate }
 * @returns {Elements}
 */
function buildItem(item, idx, config, query, callbacks) {
    const li = razyui.spell('div.' + CLS.ITEM, true);
    PART.ITEM.apply(li);

    if (razyui.isFn(config.renderItem)) {
        setContent(li, config.renderItem(item, query));
    } else if (razyui.isFn(config.itemTemplate)) {
        setContent(li, config.itemTemplate(item, query));
    } else {
        const label = razyui.isPO(item) ? String(item[config.labelKey] || '') : String(item);
        if (config.highlight && query) {
            li.html(highlightMatch(label, query, CLS.MATCH));
        } else {
            li.text(label);
        }
    }

    li.attr('data-index', idx);
    li.on('mousedown', (e) => {
        if (e.button !== 0) return;
        e.preventDefault();
        callbacks.onSelect(idx);
    });
    li.on('mouseenter', () => {
        callbacks.onActivate(idx);
    });

    return li;
}

// ═══════════════════════════════════════
//  Positioning
// ═══════════════════════════════════════

/**
 * Position the dropdown beneath (or above) the input element.
 *
 * @param {HTMLElement} inputEl  — the raw input element
 * @param {Elements}    dropdown — Elements wrapper of the dropdown
 */
export function positionDropdown(inputEl, dropdown) {
    const dd = dropdown[0];

    const { flipped } = positionFloating(dd, inputEl, {
        strategy: 'fixed',
        gap:      0,
        flip:     true,
        width:    'match',
    });

    if (flipped) {
        dropdown.addClass(CLS.FLIPPED);
    } else {
        dropdown.removeClass(CLS.FLIPPED);
    }
}

// ═══════════════════════════════════════
//  Active item management
// ═══════════════════════════════════════

/**
 * Visually highlight the active item in the dropdown and scroll it into view.
 *
 * @param {Elements} dropdown — Elements wrapper of the dropdown
 * @param {number}   idx      — index to activate (-1 = none)
 */
export function setActiveItem(dropdown, idx) {
    const items = dropdown.find('.' + CLS.ITEM);
    items.forEach((el, i) => {
        razyui(el).toggleClass(CLS.ACTIVE, i === idx);
    });

    // Scroll into view
    if (items[idx]) {
        items[idx].scrollIntoView({ block: 'nearest' });
    }
}

// ═══════════════════════════════════════
//  Cleanup
// ═══════════════════════════════════════

/**
 * Remove the dropdown element from the DOM.
 *
 * @param {Elements} dropdown — Elements wrapper of the dropdown
 */
export function cleanupDOM(dropdown) {
    dropdown[0]?.remove();
}
