/**
 * @fileoverview HintBox events — centralised event binding via AbortController.
 * @module module/HintBox/events
 */

import { HintBoxDef as DEF } from '../HintBox.def.js';
import { attachOutsideClick } from '../shared/outsideClick.js';

/**
 * Create the handler context object consumed by DEF event dispatchers.
 * Uses a lazy provider function so properties always reflect current state.
 *
 * @param {Function} provider — () => { justSelected, isOpen, itemCount, activeIdx, inputValue, minLength, onInput, setActive, select, close }
 * @returns {object} handler context with live getters / setters
 */
export function createHandlerCtx(provider) {
    return {
        get justSelected()      { return provider().justSelected; },
        set justSelected(v)     { provider().justSelected = v; },
        get isOpen()            { return provider().isOpen; },
        get itemCount()         { return provider().itemCount; },
        get activeIdx()         { return provider().activeIdx; },
        get inputValue()        { return provider().inputValue; },
        get minLength()         { return provider().minLength; },
        onInput()               { provider().onInput(); },
        setActive(idx)          { provider().setActive(idx); },
        select(idx)             { provider().select(idx); },
        close()                 { provider().close(); },
    };
}

/**
 * Bind input, keydown, and focus events on the Elements wrapper, plus an
 * outside-click listener. Returns a cleanup function that removes all bindings.
 *
 * @param {Elements}    container — Elements wrapper of the input
 * @param {HTMLElement} inputEl   — raw input element
 * @param {HTMLElement} dropdownEl — raw dropdown element
 * @param {object}      ctx       — handler context from createHandlerCtx
 * @returns {Function} cleanup — call to unbind everything
 */
export function bindEvents(container, inputEl, dropdownEl, ctx) {
    const ac = new AbortController();
    const sig = { signal: ac.signal };

    container[0].addEventListener('input', () => {
        DEF.handlers.input.input(ctx);
    }, sig);
    container[0].addEventListener('keydown', (e) => {
        DEF.handlers.input.keydown(ctx, e);
    }, sig);
    container[0].addEventListener('focus', () => {
        DEF.handlers.input.focus(ctx);
    }, sig);

    // Close on outside click
    const outsideAc = attachOutsideClick(
        inputEl, dropdownEl,
        () => { ctx.close(); },
        { scroll: true, escape: false }
    );

    // Return combined cleanup
    return function unbindAll() {
        ac.abort();
        outsideAc.abort();
    };
}
